definition.script:
import groovy.json.JsonSlurper;

def retrieveBuildSpecId;
def pipelineBuildId;
def build_hashes = [
    DICTIONARY: false,
    UPLOADER: false,
    PASSTHRU: false,
    AGGREGATE: false,
    PSL: false,
];
pipeline {
    agent any
    stages {
        stage('Retrieve Build Spec') {
            steps {
                script {
                    def result = build job: 'Retrieve Build Spec'
                    retrieveBuildSpecId = result.number
                }
                script {
                    copyArtifacts filter: '*', projectName: 'Retrieve Build Spec', selector: specific(""+retrieveBuildSpecId)
                    sh 'cat build-spec.json'
                    sh 'cat pipeline_git_commit.txt'
                    sh 'pwd'
                    def buildSpec = new JsonSlurper().parse(new File('/var/jenkins_home/workspace/PIC-SURE Pipeline/build-spec.json'))
                    pipelineBuildId = new File('/var/jenkins_home/workspace/PIC-SURE Pipeline/pipeline_git_commit.txt').text.trim()
                    for(def build : buildSpec.application){
                        build_hashes[build.project_job_git_key] = build.git_hash
                    }
                }
            }
        }
        stage('Install Logging Client Library') {
            steps {
                script {
                    try {
                        build job: 'PIC-SURE Logging Client Install', parameters: [
                            [$class: 'StringParameterValue', name: 'pipeline_build_id', value: pipelineBuildId]
                        ]
                    } catch (Exception e) {
                        echo "Logging client install failed (${e.message}). Downstream builds will proceed without it."
                    }
                }
            }
        }
        stage('PIC-SURE API') {
            steps {
                script {
                    def result = build job: 'PIC-SURE-API Build', parameters: [
                        [$class: 'StringParameterValue', name: 'pipeline_build_id', value: pipelineBuildId],
                        [$class: 'StringParameterValue', name: 'git_hash', value: build_hashes['PSA']]
                    ]
                }
            }
        }
        stage('PIC-SURE HPDS') {
            steps {
                script {
                    def result = build job: 'PIC-SURE-HPDS Build', parameters: [
                        [$class: 'StringParameterValue', name: 'pipeline_build_id', value: pipelineBuildId],
                        [$class: 'StringParameterValue', name: 'git_hash', value: build_hashes['PSH']]
                    ]
                }
            }
        }
        stage('PIC-SURE Auth') {
            steps {
                script{
                    def result = build job: 'PIC-SURE Auth Micro-App Build - Jenkinsfile', parameters: [
                        [$class: 'StringParameterValue', name: 'pipeline_build_id', value: pipelineBuildId],
                        [$class: 'StringParameterValue', name: 'git_hash', value: build_hashes['PSAMA']]
                    ]
                }
            }
        }
        stage('Frontend Build'){
            steps {
                script {
                    def result = build job: 'PIC-SURE Frontend Build', parameters: [
                        [$class: 'StringParameterValue', name: 'pipeline_build_id', value: pipelineBuildId],
                        [$class: 'StringParameterValue', name: 'git_hash', value: build_hashes['PSF']]
                    ]
                }
            }
        }
        stage('Dictionary Build & Deploy') {
            steps {
                script {
                    if (build_hashes['DICTIONARY']) {
                        def result = build job: 'PIC-SURE Dictionary API Build and Deploy', parameters: [
                            [$class: 'StringParameterValue', name: 'pipeline_build_id', value: pipelineBuildId],
                            [$class: 'StringParameterValue', name: 'git_hash', value: build_hashes['DICTIONARY']]
                        ]
                    } else {
                        echo "No project_job_git_key DICTIONARY found in build spec. Skipping Dictionary Build"
                    }
                }
            }

        }
        stage('Auxiliary Resources') {
            steps {
                parallel (
                    uploader:{
                        script {
                            if (build_hashes['UPLOADER']) {
                                echo "Building Uploader API"
                                def result = build job: 'PIC-SURE Build and Deploy Uploader', parameters: [
                                    [$class: 'StringParameterValue', name: 'pipeline_build_id', value: pipelineBuildId],
                                    [$class: 'StringParameterValue', name: 'git_hash', value: build_hashes['UPLOADER']]
                                ]
                            } else {
                                echo "No project_job_git_key UPLOADER found in build spec. Skipping Uploader Build"
                            }
                        }
                    },
                    passthru:{
                        script {
                            if (build_hashes['PASSTHRU']) {
                                echo "Building Passthru Service"
                                def result = build job: 'Build Passthru Image', parameters: [
                                    [$class: 'StringParameterValue', name: 'pipeline_build_id', value: pipelineBuildId],
                                    [$class: 'StringParameterValue', name: 'git_hash', value: build_hashes['PASSTHRU']]
                                ]
                            } else {
                                echo "No project_job_git_key PASSTHRU found in build spec. Skipping Uploader Build"
                            }
                        }
                    },
                    aggregate:{
                        script {
                            if (build_hashes['AGGREGATE']) {
                                echo "Building Aggregate Resource"
                                def result = build job: 'PIC-SURE Aggregate Resource Build', parameters: [
                                    [$class: 'StringParameterValue', name: 'pipeline_build_id', value: pipelineBuildId],
                                    [$class: 'StringParameterValue', name: 'git_hash', value: build_hashes['AGGREGATE']]
                                ]
                            } else {
                                echo "No project_job_git_key AGGREGATE found in build spec. Skipping Aggregate Resource Build"
                            }
                        }
                    },
                    logging:{
                        script {
                            if (build_hashes['PSL']) {
                                echo "Building Logging Service"
                                def result = build job: 'PIC-SURE Logging Build and Deploy', parameters: [
                                    [$class: 'StringParameterValue', name: 'git_hash', value: build_hashes['PSL']],
                                    [$class: 'StringParameterValue', name: 'DEPLOY_METHOD', value: 'docker']
                                ]
                                try {
                                    build job: 'Configure Logging'
                                } catch (Exception e) {
                                    echo "Configure Logging failed (${e.message}). Continuing pipeline."
                                }
                            } else {
                                echo "No project_job_git_key PSL found in build spec. Skipping Logging Service Build"
                            }
                        }
                    }
                )
            }
        }
    }
}
